INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation, order_index) VALUES
('9280ca36-c25a-4cdc-b6dd-2a97e8400341', 'Đọc câu sau: ''The bag is small, red and very heavy.'' Chiếc túi này có đặc điểm gì?', 'multiple_choice', '["To, màu xanh và nhẹ","Nhỏ, màu đỏ và rất nặng","Dài, màu vàng và đắt tiền","Nhỏ, màu đen và cũ"]'::jsonb, 'Nhỏ, màu đỏ và rất nặng', '''small'' là nhỏ, ''red'' là màu đỏ, ''heavy'' là nặng.', 1),
('9280ca36-c25a-4cdc-b6dd-2a97e8400341', 'Đọc câu: ''My cat is white and loves to sleep on the sofa.'' Con mèo thích làm gì?', 'multiple_choice', '["Chạy ngoài sân","Ngủ trên giường","Ăn cá","Ngủ trên ghế sofa"]'::jsonb, 'Ngủ trên ghế sofa', '''loves to sleep on the sofa'' nghĩa là thích ngủ trên ghế sofa.', 2),
('9280ca36-c25a-4cdc-b6dd-2a97e8400341', 'Đoạn văn mô tả: ''He is tall and has short black hair.'' Người đàn ông này trông như thế nào?', 'multiple_choice', '["Thấp và tóc dài","Cao và có mái tóc đen ngắn","Cao và đeo kính","Béo và có tóc nâu"]'::jsonb, 'Cao và có mái tóc đen ngắn', '''tall'' là cao, ''short black hair'' là tóc đen ngắn.', 3),
('f2fdd54b-f837-4a46-958f-6410389d5b57', 'Trong biểu mẫu đăng ký cá nhân, mục ''First Name'' yêu cầu bạn điền thông tin gì?', 'multiple_choice', '["Họ","Tên chính","Tên đệm","Biệt danh"]'::jsonb, 'Tên chính', '''First Name'' trong tiếng Anh dùng để chỉ tên gọi chính (tên thật) của bạn.', 1),
('f2fdd54b-f837-4a46-958f-6410389d5b57', 'Nếu một biểu mẫu yêu cầu điền ''Date of Birth'', bạn cần ghi gì?', 'multiple_choice', '["Nơi sinh","Số điện thoại","Ngày tháng năm sinh","Địa chỉ email"]'::jsonb, 'Ngày tháng năm sinh', '''Date of Birth'' (DOB) có nghĩa là ngày tháng năm sinh của một người.', 2),
('f2fdd54b-f837-4a46-958f-6410389d5b57', 'Ở phần ''Address'' trên các form thông tin, bạn phải điền gì?', 'multiple_choice', '["Địa chỉ nơi ở","Quốc tịch","Nghề nghiệp","Sở thích"]'::jsonb, 'Địa chỉ nơi ở', '''Address'' mang nghĩa là địa chỉ nhà ở hoặc nơi làm việc.', 3),
('40655a5a-88dd-476c-8154-79f242bb8146', 'Đọc tin nhắn sau: ''See you at 7 PM at the cinema.'' Người gửi hẹn gặp ở đâu?', 'multiple_choice', '["Quán cà phê","Rạp chiếu phim","Nhà hàng","Trường học"]'::jsonb, 'Rạp chiếu phim', '''Cinema'' có nghĩa là rạp chiếu phim.', 1),
('40655a5a-88dd-476c-8154-79f242bb8146', 'Đọc tin nhắn: ''Can you buy some milk on your way home?'' Người nhắn muốn bạn mua gì?', 'multiple_choice', '["Bánh mì","Sữa","Trứng","Cà phê"]'::jsonb, 'Sữa', '''Milk'' có nghĩa là sữa.', 2),
('40655a5a-88dd-476c-8154-79f242bb8146', 'Tin nhắn viết: ''I am running late. Wait for me for 10 minutes.'' Người gửi đang gặp tình trạng gì?', 'multiple_choice', '["Đang đến sớm","Bị lạc đường","Đang đến muộn","Quên đồ ở nhà"]'::jsonb, 'Đang đến muộn', 'Cụm ''running late'' nghĩa là đang bị trễ giờ, đến muộn.', 3),
('26ba5a31-465d-4d43-89f0-d721b676e7e8', 'Sắp xếp các từ sau thành câu đúng: ''apples / I / like / .''', 'multiple_choice', '["I apples like.","Like I apples.","Apples I like.","I like apples."]'::jsonb, 'I like apples.', 'Cấu trúc câu cơ bản Subject + Verb + Object (SVO): I (S) + like (V) + apples (O).', 1),
('26ba5a31-465d-4d43-89f0-d721b676e7e8', 'Điền từ thích hợp vào chỗ trống: ''She ___ a doctor.''', 'multiple_choice', '["am","is","are","be"]'::jsonb, 'is', 'Với chủ ngữ ngôi thứ 3 số ít ''She'', động từ ''to be'' đi kèm phải là ''is''.', 2),
('26ba5a31-465d-4d43-89f0-d721b676e7e8', 'Câu ''Tôi đi học bằng xe buýt'' dịch sang tiếng Anh đúng là gì?', 'multiple_choice', '["I go to school in bus.","I go school by bus.","I go to school by bus.","I going to school bus."]'::jsonb, 'I go to school by bus.', 'Dùng giới từ ''by'' + phương tiện giao thông (by bus) để diễn tả cách thức di chuyển.', 3),
('0e525a55-671c-4157-963e-8a0a9dbe7234', 'Bạn muốn để lại lời nhắn cho sếp báo rằng hôm nay bạn bị ốm, bạn viết câu nào?', 'multiple_choice', '["I am sick today.","I am happy today.","I am busy tomorrow.","I go to work today."]'::jsonb, 'I am sick today.', '''Sick'' nghĩa là bị ốm/bệnh.', 1),
('0e525a55-671c-4157-963e-8a0a9dbe7234', 'Bạn viết giấy nhớ để nhắc đồng nghiệp gọi lại cho bạn, bạn ghi gì?', 'multiple_choice', '["See you later.","Please call me back.","Don''t call me.","I will call you."]'::jsonb, 'Please call me back.', '''Call me back'' là yêu cầu ai đó gọi điện thoại lại cho mình.', 2),
('0e525a55-671c-4157-963e-8a0a9dbe7234', 'Bạn để lại tờ ghi chú mời bạn bè gặp mặt vào ngày mai, bạn viết câu nào?', 'multiple_choice', '["Let''s meet tomorrow.","I was there yesterday.","Where are you?","Goodbye."]'::jsonb, 'Let''s meet tomorrow.', 'Cấu trúc ''Let''s'' dùng để rủ rê/đề nghị làm gì đó, ở đây là rủ gặp mặt vào ngày mai.', 3),
('a7896af0-6023-4f51-a505-683fc444e51b', 'Để hỏi chuyến xe buýt số 5 đi đến đâu, bạn nói câu nào?', 'multiple_choice', '["Where is the bus stop?","Where does bus number 5 go?","How much is the bus?","What time is it?"]'::jsonb, 'Where does bus number 5 go?', 'Dùng ''Where does [phương tiện] go?'' để hỏi về điểm đến của chuyến đi.', 1),
('a7896af0-6023-4f51-a505-683fc444e51b', 'Câu hỏi ''How much is a ticket to London?'' được dùng với mục đích gì?', 'multiple_choice', '["Hỏi thời gian tàu chạy","Hỏi đường đến nhà ga","Hỏi giá vé","Hỏi tên hành khách"]'::jsonb, 'Hỏi giá vé', '''How much'' dùng để hỏi giá cả, ''ticket'' là vé.', 2),
('a7896af0-6023-4f51-a505-683fc444e51b', 'Khi đi xe buýt và muốn tài xế cho xuống ở trạm tiếp theo, bạn nói gì?', 'multiple_choice', '["Turn left, please.","Next stop, please.","Wait for me.","Go faster."]'::jsonb, 'Next stop, please.', '''Next stop'' có nghĩa là trạm dừng tiếp theo.', 3),
('e743f085-9e77-4bf6-9723-087d8e3ee6a1', 'Để tự giới thiệu mình đến từ Việt Nam, bạn dùng câu nào?', 'multiple_choice', '["I travel to Vietnam.","I am going to Vietnam.","I am from Vietnam.","I like Vietnam."]'::jsonb, 'I am from Vietnam.', 'Cấu trúc ''I am from + [Quốc gia]'' dùng để nói về nguồn gốc/quê quán.', 1),
('e743f085-9e77-4bf6-9723-087d8e3ee6a1', 'Khi muốn giới thiệu bạn 20 tuổi, bạn nói thế nào cho đúng?', 'multiple_choice', '["I have 20 years.","I am 20 years old.","My age has 20.","I are 20."]'::jsonb, 'I am 20 years old.', 'Tiếng Anh dùng động từ ''to be'' (I am) để nói về tuổi tác, chứ không dùng ''have'' (có).', 2),
('e743f085-9e77-4bf6-9723-087d8e3ee6a1', 'Câu ''Nice to meet you'' thường được dùng trong hoàn cảnh nào?', 'multiple_choice', '["Khi gặp ai đó lần đầu tiên","Khi đi ngủ","Khi xin lỗi","Khi đang ăn"]'::jsonb, 'Khi gặp ai đó lần đầu tiên', '''Nice to meet you'' (Rất vui được gặp bạn) là lời chào lịch sự khi lần đầu gặp mặt.', 3),
('9feac315-6479-4e15-8e5e-1bafd6936514', 'Khi bắt máy điện thoại, người bản xứ thường dùng từ gì đầu tiên?', 'multiple_choice', '["Goodbye!","Hello!","Who?","What?"]'::jsonb, 'Hello!', '''Hello'' hoặc biến thể của nó là cách phổ biến nhất để mở đầu cuộc điện thoại.', 1),
('9feac315-6479-4e15-8e5e-1bafd6936514', 'Để lịch sự yêu cầu gặp Mary qua điện thoại, bạn nói gì?', 'multiple_choice', '["Give me Mary.","Mary, where are you?","Can I speak to Mary, please?","I want Mary now."]'::jsonb, 'Can I speak to Mary, please?', 'Cấu trúc ''Can I speak to + [Tên người], please?'' là cách lịch sự nhất để xin nói chuyện với ai đó.', 2),
('9feac315-6479-4e15-8e5e-1bafd6936514', 'Khi người ở đầu dây bên kia nói ''Hold on, please'', họ muốn bạn làm gì?', 'multiple_choice', '["Cúp máy ngay lập tức","Nói to hơn","Gọi lại sau","Vui lòng giữ máy chờ một chút"]'::jsonb, 'Vui lòng giữ máy chờ một chút', 'Cụm ''Hold on'' trong giao tiếp điện thoại có nghĩa là giữ máy không cúp.', 3),
('ed37c1b3-8c54-4ac2-b417-08e80573ebf9', 'Tại nhà hàng, để gọi món ''gà rán'', bạn nói câu nào?', 'multiple_choice', '["I would like some fried chicken.","I don''t like chicken.","Where is the chicken?","Chicken is flying."]'::jsonb, 'I would like some fried chicken.', '''I would like'' (Tôi muốn) là cấu trúc phổ biến và lịch sự để gọi món, ''fried chicken'' là gà rán.', 1),
('ed37c1b3-8c54-4ac2-b417-08e80573ebf9', 'Khi đã dùng bữa xong và muốn thanh toán, bạn nói câu nào với bồi bàn?', 'multiple_choice', '["More food, please.","Can I have the bill, please?","Where is the toilet?","I want to go home."]'::jsonb, 'Can I have the bill, please?', '''The bill'' (tiếng Anh Anh) hoặc ''The check'' (tiếng Anh Mỹ) mang nghĩa là hóa đơn tính tiền.', 2),
('ed37c1b3-8c54-4ac2-b417-08e80573ebf9', 'Khi nhân viên quán cà phê hỏi ''For here or to go?'', họ đang muốn biết điều gì?', 'multiple_choice', '["Bạn thích ăn món gì?","Bạn uống cà phê có đường không?","Bạn dùng tại chỗ hay mang đi?","Bạn trả bằng tiền mặt hay thẻ?"]'::jsonb, 'Bạn dùng tại chỗ hay mang đi?', '''For here'' là ăn/uống tại quán, ''to go'' là mang đi.', 3),
('c9f711b8-bfb0-48cb-a174-ac94b060fd0a', 'Để hỏi đường đến ngân hàng gần nhất, bạn sử dụng câu nào?', 'multiple_choice', '["What time does the bank close?","Where is the nearest bank?","Is this a bank?","Do you work at a bank?"]'::jsonb, 'Where is the nearest bank?', '''Where is...'' dùng để hỏi vị trí, ''nearest'' là gần nhất.', 1),
('c9f711b8-bfb0-48cb-a174-ac94b060fd0a', 'Người dân địa phương chỉ đường ''Go straight and turn left''. Bạn phải đi như thế nào?', 'multiple_choice', '["Đi lùi và rẽ phải","Đứng yên một chỗ","Đi thẳng và rẽ trái","Quay đầu lại"]'::jsonb, 'Đi thẳng và rẽ trái', '''Go straight'' là đi thẳng, ''turn left'' là rẽ trái.', 2),
('c9f711b8-bfb0-48cb-a174-ac94b060fd0a', 'Câu chỉ dẫn ''It''s on your right'' mang ý nghĩa gì?', 'multiple_choice', '["Nó ở bên phải của bạn","Nó ở bên trái của bạn","Bạn đi sai đường rồi","Nó ở ngay phía sau"]'::jsonb, 'Nó ở bên phải của bạn', '''On your right'' chỉ vị trí nằm ở phía bên tay phải của người nghe.', 3),
('47949187-676f-4d4b-805f-109c51a9a410', 'Khi gặp tai nạn và cần gọi xe cấp cứu, bạn nên hô lên từ gì?', 'multiple_choice', '["Taxi!","Ambulance!","Fire!","Police!"]'::jsonb, 'Ambulance!', '''Ambulance'' nghĩa là xe cứu thương.', 1),
('47949187-676f-4d4b-805f-109c51a9a410', 'Nếu bạn đang đi du lịch và không biết mình đang ở đâu, bạn nói với người khác câu nào?', 'multiple_choice', '["I am happy.","I am hungry.","I am lost.","I am tired."]'::jsonb, 'I am lost.', 'Cụm ''I am lost'' nghĩa là ''Tôi bị lạc đường''.', 2),
('47949187-676f-4d4b-805f-109c51a9a410', 'Câu ''Call the police!'' nên được sử dụng trong tình huống nào dưới đây?', 'multiple_choice', '["Khi gặp người quen cũ","Khi bị cướp hoặc gặp nguy hiểm","Khi muốn mua vé xe","Khi xe bị thủng lốp"]'::jsonb, 'Khi bị cướp hoặc gặp nguy hiểm', '''Call the police'' (Hãy gọi cảnh sát) được dùng trong các trường hợp an ninh khẩn cấp.', 3),
('b24cb239-f543-4ac8-b97f-9974e5a2c828', 'Để hỏi giá một chiếc áo sơ mi trong cửa hàng, bạn nói câu nào?', 'multiple_choice', '["How old is this shirt?","How much is this shirt?","What color is this?","Where is the shirt?"]'::jsonb, 'How much is this shirt?', 'Cấu trúc ''How much is...'' dùng để hỏi giá tiền của một đồ vật.', 1),
('b24cb239-f543-4ac8-b97f-9974e5a2c828', 'Nếu mặc áo bị chật và muốn xin một cỡ lớn hơn, bạn nói thế nào?', 'multiple_choice', '["Do you have this in a larger size?","Can I have a smaller one?","I don''t like this color.","Is this for kids?"]'::jsonb, 'Do you have this in a larger size?', '''Larger size'' có nghĩa là kích cỡ lớn hơn.', 2),
('b24cb239-f543-4ac8-b97f-9974e5a2c828', 'Câu ''I''ll take it'' thường được nói trong tình huống nào khi đi mua sắm?', 'multiple_choice', '["Khi bạn muốn trả lại hàng","Khi bạn đang phân vân","Khi bạn quyết định sẽ mua món đồ đó","Khi bạn chê đồ quá đắt"]'::jsonb, 'Khi bạn quyết định sẽ mua món đồ đó', '''I''ll take it'' (Tôi sẽ lấy món này) dùng để chốt mua sản phẩm.', 3),
('cccc0001-0001-0001-0001-000000000012', 'Hành động ''đánh răng'' mỗi sáng trong tiếng Anh được gọi là gì?', 'multiple_choice', '["Wash face","Brush teeth","Comb hair","Get dressed"]'::jsonb, 'Brush teeth', '''Brush'' là chải/đánh, ''teeth'' là răng.', 1),
('cccc0001-0001-0001-0001-000000000005', 'Từ vựng nào dưới đây mang nghĩa là ''nước ép trái cây''?', 'multiple_choice', '["Milk","Water","Juice","Coffee"]'::jsonb, 'Juice', '''Juice'' là nước ép (ví dụ: orange juice, apple juice).', 1),
('cccc0001-0001-0001-0001-000000000009', 'Phòng được dùng để nấu ăn trong một ngôi nhà tiếng Anh gọi là gì?', 'multiple_choice', '["Bedroom","Bathroom","Living room","Kitchen"]'::jsonb, 'Kitchen', '''Kitchen'' là nhà bếp. Bedroom là phòng ngủ, Bathroom là phòng tắm, Living room là phòng khách.', 1),
('cccc0001-0001-0001-0001-000000000006', 'Người làm công việc khám và chữa bệnh ở bệnh viện tiếng Anh gọi là gì?', 'multiple_choice', '["Teacher","Farmer","Doctor","Driver"]'::jsonb, 'Doctor', '''Doctor'' là bác sĩ.', 1),
('cccc0001-0001-0001-0001-000000000011', 'Phương tiện ''xe đạp'' trong tiếng Anh là gì?', 'multiple_choice', '["Car","Bus","Bicycle","Train"]'::jsonb, 'Bicycle', '''Bicycle'' (hay gọi tắt là bike) là xe đạp.', 1),
('cccc0001-0001-0001-0001-000000000008', 'Tính từ chỉ thời tiết ''có nắng'' trong tiếng Anh là gì?', 'multiple_choice', '["Rainy","Cloudy","Windy","Sunny"]'::jsonb, 'Sunny', '''Sun'' là mặt trời, ''Sunny'' là trạng thái thời tiết có nắng.', 1);